/* ============================================================
   TYPES
   ============================================================ */
type InputSize = 'sm' | 'md' | 'lg';
type InputState = 'default' | 'error' | 'disabled';

interface InputProps
  extends Omit<React.InputHTMLAttributes<HTMLInputElement>, 'size'> {
  /** Visual size variant — maps to Figma Size=SM/MD/LG */
  size?: InputSize;
  /** Drives error border/color (Figma State=Error) */
  hasError?: boolean;
  /** Error message displayed below the input */
  errorMessage?: string;
  /** Helper text displayed below the input (superseded by errorMessage) */
  helperText?: string;
  /** Label text rendered above the input */
  label?: string;
  /** Icon rendered inside the input on the left */
  iconLeft?: React.ReactNode;
  /** Icon rendered inside the input on the right */
  iconRight?: React.ReactNode;
}

/* ============================================================
   COMPONENT
   ============================================================ */
const Input = forwardRef<HTMLInputElement, InputProps>(
  (
    {
      size = 'md',
      hasError = false,
      errorMessage,
      helperText,
      label,
      iconLeft,
      iconRight,
      id: externalId,
      className,
      disabled,
      ...rest
    },
    ref
  ) => {
    const generatedId = useId();
    const id = externalId ?? generatedId;
    const helperId = `${id}-helper`;

    /* BEM class composition */
    const inputClasses = [
      'input',
      `input--${size}`,
      hasError && !disabled ? 'input--error' : '',
      disabled ? 'input--disabled' : '',
      iconLeft ? 'input--has-icon-left' : '',
      iconRight ? 'input--has-icon-right' : '',
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    const wrapperClasses = [
      'input-wrapper',
      iconLeft || iconRight ? 'input-wrapper--with-icon' : '',
    ]
      .filter(Boolean)
      .join(' ');

    const displayedHelper = hasError ? errorMessage : helperText;
    const helperClass = [
      'input__helper',
      hasError ? 'input__helper--error' : '',
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <div className={wrapperClasses}>
        {label && (
          <label htmlFor={id} className="input__label">
            {label}
          </label>
        )}

        <div style={{ position: 'relative' }}>
          {iconLeft && (
            <span
              className="input__icon input__icon--left"
              aria-hidden="true"
            >
              {iconLeft}
            </span>
          )}

          <input
            ref={ref}
            id={id}
            className={inputClasses}
            disabled={disabled}
            aria-invalid={hasError ? 'true' : undefined}
            aria-describedby={displayedHelper ? helperId : undefined}
            {...rest}
          />

          {iconRight && (
            <span
              className="input__icon input__icon--right"
              aria-hidden="true"
            >
              {iconRight}
            </span>
          )}
        </div>

        {displayedHelper && (
          <span id={helperId} className={helperClass} role={hasError ? 'alert' : undefined}>
            {displayedHelper}
          </span>
        )}
      </div>
    );
  }
);

Input.displayName = 'Input';

