  --component-card-radius:     var(--semantic-radius-lg,               12px);
  --component-card-shadow:     var(--semantic-shadow-100,              0px 1px 3px 0px rgba(0,0,0,0.1));

  /* ⚠️ TOKEN_MANQUANT: component.card.padding.sm — Figma: 16px */
  --component-card-padding-sm: var(--semantic-spacing-md,             16px);

  /* ⚠️ TOKEN_MANQUANT: component.card.padding.md — Figma: 24px */
  --component-card-padding-md: var(--semantic-spacing-lg,             24px);

  /* ⚠️ TOKEN_MANQUANT: component.card.padding.lg — Figma: 32px */
  --component-card-padding-lg: var(--semantic-spacing-xl,             32px);
}


.card {
