}

.card--interactive:active:not(:disabled) {
  box-shadow: var(--component-card-shadow);
  transform:  translateY(0px);
}

.card--interactive:focus-visible {
  outline:        2px solid var(--semantic-color-border-emphasis, #3B82F6);
  outline-offset: 2px;
}


.card--flat {
  box-shadow: none;
  border:     none;
}`;

import './card.css';

/* ============================================================
   Types
   ============================================================ */
type CardSize        = 'sm' | 'md' | 'lg';
type CardVariant     = 'default' | 'flat' | 'interactive';

interface CardProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Figma Size= variants — sm:16px / md:24px / lg:32px padding */
  size?:        CardSize;
  /** Visual variant */
  variant?:     CardVariant;
  /** Slot: title text */
  title?:       React.ReactNode;
  /** Slot: subtitle text (below title) */
  subtitle?:    React.ReactNode;
  /** Slot: footer content */
  footer?:      React.ReactNode;
  /** Main content */
  children?:    React.ReactNode;
  /** Extra class names */
  className?:   string;
}

/* ============================================================
   Component
   ============================================================ */
const Card = React.forwardRef<HTMLDivElement, CardProps>(
  (
    {
      size      = 'md',
      variant   = 'default',
      title,
      subtitle,
      footer,
      children,
      className = '',
      ...rest
    },
    ref
  ) => {
    const modifiers = [
      `card--${size}`,
      variant !== 'default' ? `card--${variant}` : '',
    ]
      .filter(Boolean)
      .join(' ');

    const hasHeader = title || subtitle;

    return (
      <div
        ref={ref}
        className={['card', modifiers, className].filter(Boolean).join(' ')}
        /* a11y: if interactive, ensure keyboard access via tabIndex */
        tabIndex={variant === 'interactive' ? 0 : undefined}
        role={variant === 'interactive' ? 'button' : undefined}
        {...rest}
      >
        {hasHeader && (
          <header className="card__header">
            {title    && <h3 className="card__title">{title}</h3>}
            {subtitle && <p  className="card__subtitle">{subtitle}</p>}
          </header>
        )}

        {children && (
          <div className="card__body">{children}</div>
        )}

        {footer && (
          <footer className="card__footer">{footer}</footer>
        )}
      </div>
    );
  }
);

Card.displayName = 'Card';

/* ============================================================
   Default ============================================================ */
Card;

/* ============================================================
   STORYBOOK / DEMO RENDER — visual matrix
   ============================================================ */
const CardDemoMatrix: React.FC = () => {
  const sizes: CardSize[]        = ['sm', 'md', 'lg'];
  const variants: CardVariant[]  = ['default', 'flat', 'interactive'];

  const sampleContent = (
    <>
      The quick brown fox jumps over the lazy dog. This card body text uses
      the <em>body</em> typography token.
    </>
  );

  const sampleFooter = (
    <>
      <span style={{ fontSize: '0.75rem', color: 'var(--semantic-color-text-secondary, #6B7280)' }}>
        Footer label
      </span>
      <button
        style={{
          marginLeft: 'auto',
          padding: '4px 12px',
          borderRadius: '6px',
          border: '1px solid var(--semantic-color-border-default, #E5E7EB)',
          background: 'transparent',
          cursor: 'pointer',
          fontSize: '0.875rem',
        }}
      >
        Action
      </button>
    </>
  );

  return (
    <div
      style={{
        display:       'flex',
        flexDirection: 'column',
        gap:           '48px',
        padding:       '32px',
        background:    '#F9FAFB',
        fontFamily:    'sans-serif',
      }}
    >
      <h2 style={{ margin: 0, fontSize: '1rem', color: '#374151' }}>
        Card — Variant × Size matrix
      </h2>

      {variants.map((variant) => (
        <section key={variant}>
          {/* Variant label */}
          <p
            style={{
              margin:       '0 0 16px',
              fontSize:     '0.75rem',
              fontWeight:   600,
              textTransform:'uppercase',
              letterSpacing:'0.05em',
              color:        '#9CA3AF',
            }}
          >
            variant={variant}
          </p>

          <div
            style={{
              display:      'grid',
              gridTemplateColumns: 'repeat(3, minmax(240px, 1fr))',
              gap:          '24px',
            }}
          >
            {sizes.map((size) => (
              <div key={size}>
                {/* Size label */}
                <p
                  style={{
                    margin:     '0 0 8px',
                    fontSize:   '0.7rem',
                    color:      '#6B7280',
                    fontWeight: 500,
                  }}
                >
                  size={size} — padding:{' '}
                  {size === 'sm' ? '16px' : size === 'md' ? '24px' : '32px'}
                </p>

                <Card
                  size={size}
                  variant={variant}
                  title="Card title"
                  subtitle="Supporting subtitle text"
                  footer={sampleFooter}
                >
                  {sampleContent}
                </Card>
              </div>
            ))}
          </div>
        </section>
      ))}

      {/* Edge cases */}
      <section>
        <p
          style={{
            margin:       '0 0 16px',
            fontSize:     '0.75rem',
            fontWeight:   600,
            textTransform:'uppercase',
            letterSpacing:'0.05em',
            color:        '#9CA3AF',
          }}
        >
          edge cases
        </p>

        <div
          style={{
            display:             'grid',
            gridTemplateColumns: 'repeat(3, minmax(240px, 1fr))',
            gap:                 '24px',
          }}
        >
          {/* No header */}
          <div>
            <p style={{ margin: '0 0 8px', fontSize: '0.7rem', color: '#6B7280' }}>
              No header (body only)
            </p>
            <Card size="md">{sampleContent}</Card>
          </div>

          {/* No footer */}
          <div>
            <p style={{ margin: '0 0 8px', fontSize: '0.7rem', color: '#6B7280' }}>
              No footer
            </p>
            <Card size="md" title="Title only" subtitle="No footer here">
              {sampleContent}
            </Card>
          </div>

          {/* Empty card */}
          <div>
            <p style={{ margin: '0 0 8px', fontSize: '0.7rem', color: '#6B7280' }}>
              Empty card (structure only)
            </p>
            <Card size="md" style={{ minHeight: '80px' }} />
          </div>
        </div>
      </section>
    </div>
  );
};

render(<><style>{__css}</style><Card /></>);
