import './badge.css';

/* ─────────────────────────────────────────────
   Types
───────────────────────────────────────────── */
type BadgeVariant = 'primary' | 'success' | 'warning' | 'danger' | 'neutral';

interface BadgeProps {
  /** Variant visuelle — mappe sur les variantes Figma */
  variant?: BadgeVariant;
  /** Contenu textuel du badge */
  children: React.ReactNode;
  /** Icône optionnelle positionnée avant le label */
  leadingIcon?: React.ReactNode;
  /** Icône optionnelle positionnée après le label */
  trailingIcon?: React.ReactNode;
  /** Classes CSS additionnelles */
  className?: string;
  /** aria-label pour les badges purement iconiques */
  ariaLabel?: string;
}

/* ─────────────────────────────────────────────
   Component
───────────────────────────────────────────── */
const Badge: React.FC<BadgeProps> = ({
  variant = 'primary',
  children,
  leadingIcon,
  trailingIcon,
  className = '',
  ariaLabel,
}) => {
  const rootClass = [
    'badge',
    `badge--${variant}`,
    className,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <span
      className={rootClass}
      aria-label={ariaLabel}
      role="status"
    >
      {leadingIcon && (
        <span className="badge__icon" aria-hidden="true">
          {leadingIcon}
        </span>
      )}
      <span className="badge__label">{children}</span>
      {trailingIcon && (
        <span className="badge__icon" aria-hidden="true">
          {trailingIcon}
        </span>
      )}
    </span>
  );
};

Badge.displayName = 'Badge';

Badge;

/* ─────────────────────────────────────────────
   Storybook Demo — matrice complète des variantes
   (à placer dans Badge.stories.tsx)
───────────────────────────────────────────── */
