        >
          {VARIANTS.map((variant) => (
            <Badge key={variant} variant={variant} leadingIcon={<DotIcon />}>
              {VARIANT_LABELS[variant]}
            </Badge>
          ))}
        </div>
      </section>
    </div>
  );
};

render(<><style>{__css}</style><Badge /></>);
```

